def token_f1(a_tokens, b_tokens):
    ca = Counter(a_tokens)
    cb = Counter(b_tokens)
    overlap = sum( min(ca[t], cb.get(t,0)) for t in ca )
    if overlap == 0:
        return 0.0, 0, len(a_tokens), len(b_tokens)
    prec = overlap / len(a_tokens)
    rec = overlap / len(b_tokens)
    if prec + rec == 0:
        f1 = 0.0
    else:
        f1 = 2*prec*rec/(prec+rec)
    return f1, overlap, len(a_tokens), len(b_tokens)

